package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.util.ArrayList;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class NonNullElementWrapperListTest {

  NonNullElementWrapperList<String> list;
  ArrayList<String> delegate;

  @BeforeEach
  void setUp() {
    delegate = mock(ArrayList.class);
    list = new NonNullElementWrapperList<>(delegate);
  }

  @Test
  void equals_sameDelegateObject_returnsTrue() {
    when(delegate.equals(delegate)).thenReturn(true);
    assertTrue(list.equals(delegate));
  }

  @Test
  void equals_nullObject_returnsFalse() {
    when(delegate.equals(null)).thenReturn(false);
    assertFalse(list.equals(null));
  }

  @Test
  void equals_differentObject_returnsFalse() {
    Object other = new Object();
    when(delegate.equals(other)).thenReturn(false);
    assertFalse(list.equals(other));
  }

  @Test
  void equals_delegateEqualsReturnsTrue_returnsTrue() {
    Object other = new ArrayList<String>();
    when(delegate.equals(other)).thenReturn(true);
    assertTrue(list.equals(other));
  }

  @Test
  void equals_delegateEqualsReturnsFalse_returnsFalse() {
    Object other = new ArrayList<String>();
    when(delegate.equals(other)).thenReturn(false);
    assertFalse(list.equals(other));
  }
}
